import{_ as o,C as s,o as r,c as d,aw as l,E as n,w as a,j as e}from"./chunks/framework.DLufY-ao.js";const m="/workbook/assets/ddd1.C767Mu6f.jpg",u="/workbook/assets/ddd2.C8mh1FlE.jpg",v=JSON.parse('{"title":"Domain-Driven Design (DDD)","description":"","frontmatter":{},"headers":[],"relativePath":"wiki/dev-commit/theory/methodology-dev/principles/ddd.md","filePath":"wiki/dev-commit/theory/methodology-dev/principles/ddd.md"}'),D={name:"wiki/dev-commit/theory/methodology-dev/principles/ddd.md"};function c(h,i,g,_,p,b){const t=s("v-two");return r(),d("div",null,[i[2]||(i[2]=l('<h1 id="domain-driven-design-ddd" tabindex="-1">Domain-Driven Design (DDD) <a class="header-anchor" href="#domain-driven-design-ddd" aria-label="Permalink to &quot;Domain-Driven Design (DDD)&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Domain-Driven Design</p><ul><li><strong>Domain-Driven Design (DDD)</strong> (предметно-ориентированное проектирование) - набор принципов и схем, направленных на создание оптимальных систем объектов. Сводится к созданию программных абстракций, которые называются моделями предметных областей. В эти модели входит бизнес-логика, устанавливающая связь между реальными условиями области применения продукта и кодом</li><li>DDD - набор правил, которые позволяют принимать правильные проектные решения. Данный подход позволяет значительно ускорить процесс проектирования программного обеспечения в незнакомой предметной области</li><li>DDD - набор подходов для организации кода в системах со сложной предметной областью</li><li>Подход DDD особо полезен в ситуациях, когда разработчик не является специалистом в области разрабатываемого продукта. К примеру: программист не может знать все области, в которых требуется создать ПО, но с помощью правильного представления структуры, посредством проблемно-ориентированного подхода, может без труда спроектировать приложение, основываясь на ключевых моментах и знаниях рабочей области</li><li>Приложение должно максимально рассказыать какую предметную область решаем</li></ul></div><h2 id="применение" tabindex="-1">Применение <a class="header-anchor" href="#применение" aria-label="Permalink to &quot;Применение&quot;">​</a></h2><ul><li>Проекты с тяжелой бизнес-логикой</li><li>Проекты, которые сложно разграничить</li></ul><h2 id="структура" tabindex="-1">Структура <a class="header-anchor" href="#структура" aria-label="Permalink to &quot;Структура&quot;">​</a></h2><h3 id="определения" tabindex="-1">Определения <a class="header-anchor" href="#определения" aria-label="Permalink to &quot;Определения&quot;">​</a></h3><ul><li><strong>Domain</strong> (Область) - сущность или действия реального мира, которые пытаемся автоматизировать. Предметная область, к которой применяется разрабатываемое ПО</li><li><strong>Model</strong> (Модель) - описывает отдельные аспекты области и может быть использована для решения проблемы</li><li><strong>Ubiquitous Language</strong> (Единый язык домена) - набор терминов, применяемых в модели домена для объяснения связей и дейтствий. Используется для единого стиля описания домена и модели. Необходим для постоения правильного взаимодействия между доменными специалистами (бизнес-аналитиками, аналитиками, PM, заказчиком) и разработчиками, чтобы могли общаться на одном языке</li><li><strong>Bounded Context</strong> - контекст, ограничивающий Domain Model и Ubiquitous Language</li></ul>',7)),n(t,null,{first:a(()=>[...i[0]||(i[0]=[e("img",{src:m,style:{width:"350px"}},null,-1)])]),last:a(()=>[...i[1]||(i[1]=[e("img",{src:u,style:{width:"350px"}},null,-1)])]),_:1}),i[3]||(i[3]=l('<h3 id="алгоритм" tabindex="-1">Алгоритм <a class="header-anchor" href="#алгоритм" aria-label="Permalink to &quot;Алгоритм&quot;">​</a></h3><ul><li>Есть домен, котрый является определенной бизнес-задачей</li><li>Далее идёт разбиение на поддомены - те действующий элементы проекта, который составляют основной функционал</li></ul><h3 id="поддомены" tabindex="-1">Поддомены <a class="header-anchor" href="#поддомены" aria-label="Permalink to &quot;Поддомены&quot;">​</a></h3><ol><li><strong>Core Domain</strong> (Ядро домена) - основной бизнес-процесс. Основная задача DDD - вычленить его</li><li><strong>Supporting Domain</strong> - от них зависит бизнес, но которые не имеют прямого отношения к ядру. Что-то помогающее бизнес-процессу</li></ol><h2 id="архитектурные-решения" tabindex="-1">Архитектурные решения <a class="header-anchor" href="#архитектурные-решения" aria-label="Permalink to &quot;Архитектурные решения&quot;">​</a></h2><ul><li><strong>Model-Driven Design</strong> - проектирование от модели</li><li><strong>CQRS</strong> - архитектурный подход. Разделение представления данных как со сторный БД, так и внутри самого приложения</li></ul><h2 id="шаблоны-проектирования-часто-используемые-с-ddd" tabindex="-1">Шаблоны проектирования, часто используемые с DDD <a class="header-anchor" href="#шаблоны-проектирования-часто-используемые-с-ddd" aria-label="Permalink to &quot;Шаблоны проектирования, часто используемые с DDD&quot;">​</a></h2><details class="details custom-block"><summary>1. Entity</summary><ul><li>Описывает индивидуально существующие элементы домена</li><li>Определяется по идентификатору, а не по значению атрибутов</li><li>Непрерывно и однозначно определяется на всем протяжении существования</li></ul></details><details class="details custom-block"><summary>2. Value Object</summary><ul><li>Не обладается идентификатором</li><li>Описывает элементы домена, полностью определяемые свойствами</li><li>Неизменяемый после создания</li><li>Используется для типизации и структурирования данных</li></ul></details><details class="details custom-block"><summary>3. Aggregate</summary><ul><li>Собирательная сущность, которая считаетмя единым целым</li><li>Состоит из Value Object и Entity</li><li>Определяется по идентификатору</li><li>Является границей транзакции при изменении данных</li><li>Другие элементы домена не могут ссылаться на внтренности агрегата</li></ul></details><details class="details custom-block"><summary>4. Respository</summary><ul><li>Описывается интерфейсом</li><li>Объекты не зависят от структуры БД и типов полей</li><li>В рамках доменного слоя реализация не важна</li><li>Может быть реализован для разных хранилищ</li><li>Удобно тестировать</li><li>Хорошо ложится в DDD</li><li>Сложно со старта</li><li>Входной порог существенно выше</li><li>Придётся писать гидраторы</li></ul></details><details class="details custom-block"><summary>5. Service</summary></details>',12))])}const y=o(D,[["render",c]]);export{v as __pageData,y as default};
